import{_ as s,o as t,c as n,ag as e}from"./chunks/framework.BVdG3tbf.js";const u=JSON.parse('{"title":"ANSYS 安装与配置","description":"","frontmatter":{},"headers":[],"relativePath":"ansys/basics/installation.md","filePath":"ansys/basics/installation.md","lastUpdated":1774417890000}'),l={name:"ansys/basics/installation.md"};function p(d,a,i,r,o,c){return t(),n("div",null,[...a[0]||(a[0]=[e(`<h1 id="ansys-安装与配置" tabindex="-1">ANSYS 安装与配置 <a class="header-anchor" href="#ansys-安装与配置" aria-label="Permalink to &quot;ANSYS 安装与配置&quot;">​</a></h1><p>本教程将指导你完成 ANSYS 的安装和基本配置。</p><h2 id="📋-系统要求" tabindex="-1">📋 系统要求 <a class="header-anchor" href="#📋-系统要求" aria-label="Permalink to &quot;📋 系统要求&quot;">​</a></h2><h3 id="硬件要求" tabindex="-1">硬件要求 <a class="header-anchor" href="#硬件要求" aria-label="Permalink to &quot;硬件要求&quot;">​</a></h3><table tabindex="0"><thead><tr><th>配置</th><th>最低要求</th><th>推荐配置</th></tr></thead><tbody><tr><td><strong>处理器</strong></td><td>Intel/AMD 64位</td><td>多核处理器 (16核+)</td></tr><tr><td><strong>内存</strong></td><td>8 GB</td><td>64 GB 或更高</td></tr><tr><td><strong>硬盘</strong></td><td>20 GB</td><td>SSD 200 GB+</td></tr><tr><td><strong>显卡</strong></td><td>支持 OpenGL</td><td>专业显卡 (NVIDIA Quadro/RTX)</td></tr></tbody></table><h3 id="操作系统" tabindex="-1">操作系统 <a class="header-anchor" href="#操作系统" aria-label="Permalink to &quot;操作系统&quot;">​</a></h3><ul><li>Windows 10/11 (64位) ✅ 推荐</li><li>Linux (RHEL 7/8, CentOS 7/8, Ubuntu 18.04/20.04)</li></ul><h2 id="🔧-安装步骤" tabindex="-1">🔧 安装步骤 <a class="header-anchor" href="#🔧-安装步骤" aria-label="Permalink to &quot;🔧 安装步骤&quot;">​</a></h2><h3 id="步骤-1-下载安装包" tabindex="-1">步骤 1：下载安装包 <a class="header-anchor" href="#步骤-1-下载安装包" aria-label="Permalink to &quot;步骤 1：下载安装包&quot;">​</a></h3><ol><li>访问 <a href="https://www.ansys.com" target="_blank" rel="noreferrer">ANSYS 官网</a></li><li>登录或注册账号</li><li>下载 ANSYS 安装管理器</li></ol><h3 id="步骤-2-运行安装程序" tabindex="-1">步骤 2：运行安装程序 <a class="header-anchor" href="#步骤-2-运行安装程序" aria-label="Permalink to &quot;步骤 2：运行安装程序&quot;">​</a></h3><p><strong>Windows:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>双击运行 setup.exe</span></span>
<span class="line"><span>→ 选择&quot;Install ANSYS Products&quot;</span></span>
<span class="line"><span>→ 接受许可协议</span></span>
<span class="line"><span>→ 选择安装目录</span></span></code></pre></div><h3 id="步骤-3-选择产品" tabindex="-1">步骤 3：选择产品 <a class="header-anchor" href="#步骤-3-选择产品" aria-label="Permalink to &quot;步骤 3：选择产品&quot;">​</a></h3><p>推荐安装的产品：</p><table tabindex="0"><thead><tr><th>产品</th><th>用途</th><th>推荐</th></tr></thead><tbody><tr><td><strong>Workbench</strong></td><td>统一仿真平台</td><td>✅ 必装</td></tr><tr><td><strong>Mechanical APDL</strong></td><td>结构分析</td><td>✅ 推荐</td></tr><tr><td><strong>Mechanical</strong></td><td>结构分析（GUI）</td><td>✅ 推荐</td></tr><tr><td><strong>Fluent</strong></td><td>流体分析</td><td>✅ 推荐</td></tr><tr><td><strong>CFX</strong></td><td>流体分析</td><td>可选</td></tr><tr><td><strong>Icepak</strong></td><td>电子热管理</td><td>✅ 电子封装推荐</td></tr><tr><td><strong>Maxwell</strong></td><td>电磁分析</td><td>可选</td></tr><tr><td><strong>SpaceClaim</strong></td><td>几何建模</td><td>✅ 推荐</td></tr></tbody></table><h3 id="步骤-4-配置许可证" tabindex="-1">步骤 4：配置许可证 <a class="header-anchor" href="#步骤-4-配置许可证" aria-label="Permalink to &quot;步骤 4：配置许可证&quot;">​</a></h3><p><strong>学生版（免费）：</strong></p><ul><li>下载 ANSYS Student 版</li><li>功能有限但免费</li></ul><p><strong>商业版：</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>许可证配置:</span></span>
<span class="line"><span>├── 许可证类型: FlexNet</span></span>
<span class="line"><span>├── 服务器地址: port@server</span></span>
<span class="line"><span>└── 例如: 2325@license-server.company.com</span></span></code></pre></div><h2 id="⚙️-workbench-界面介绍" tabindex="-1">⚙️ Workbench 界面介绍 <a class="header-anchor" href="#⚙️-workbench-界面介绍" aria-label="Permalink to &quot;⚙️ Workbench 界面介绍&quot;">​</a></h2><h3 id="主界面布局" tabindex="-1">主界面布局 <a class="header-anchor" href="#主界面布局" aria-label="Permalink to &quot;主界面布局&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  菜单栏  文件  编辑  视图  工具  帮助                      │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  工具箱                                                 │</span></span>
<span class="line"><span>│  ├ 分析系统                                            │</span></span>
<span class="line"><span>│  │  ├ Static Structural                               │</span></span>
<span class="line"><span>│  │  ├ Steady-State Thermal                            │</span></span>
<span class="line"><span>│  │  ├ Fluent                                          │</span></span>
<span class="line"><span>│  │  └ ...                                             │</span></span>
<span class="line"><span>│  ├ 组件系统                                            │</span></span>
<span class="line"><span>│  ├ 自定义系统                                          │</span></span>
<span class="line"><span>│  └ 设计探索                                            │</span></span>
<span class="line"><span>├──────────────┬──────────────────────────────────────────┤</span></span>
<span class="line"><span>│              │                                          │</span></span>
<span class="line"><span>│  项目原理图   │          图形区域                        │</span></span>
<span class="line"><span>│              │                                          │</span></span>
<span class="line"><span>│  A: Static   │      ┌──────────────┐                   │</span></span>
<span class="line"><span>│  Structural  │      │              │                   │</span></span>
<span class="line"><span>│  ├ Engineering Data │   几何/结果   │                   │</span></span>
<span class="line"><span>│  ├ Geometry  │      │              │                   │</span></span>
<span class="line"><span>│  ├ Model     │      └──────────────┘                   │</span></span>
<span class="line"><span>│  ├ Setup     │                                          │</span></span>
<span class="line"><span>│  ├ Solution  │                                          │</span></span>
<span class="line"><span>│  └ Results   │                                          │</span></span>
<span class="line"><span>│              │                                          │</span></span>
<span class="line"><span>├──────────────┴──────────────────────────────────────────┤</span></span>
<span class="line"><span>│  信息窗口 / 进程窗口                                     │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="分析系统" tabindex="-1">分析系统 <a class="header-anchor" href="#分析系统" aria-label="Permalink to &quot;分析系统&quot;">​</a></h3><table tabindex="0"><thead><tr><th>系统</th><th>用途</th><th>物理场</th></tr></thead><tbody><tr><td><strong>Static Structural</strong></td><td>静态结构分析</td><td>力学</td></tr><tr><td><strong>Transient Structural</strong></td><td>瞬态结构分析</td><td>力学</td></tr><tr><td><strong>Steady-State Thermal</strong></td><td>稳态热分析</td><td>热</td></tr><tr><td><strong>Transient Thermal</strong></td><td>瞬态热分析</td><td>热</td></tr><tr><td><strong>Thermal-Static Structural</strong></td><td>热-结构耦合</td><td>热+力学</td></tr><tr><td><strong>Electric</strong></td><td>电场分析</td><td>电</td></tr><tr><td><strong>Thermal-Electric</strong></td><td>热-电耦合</td><td>热+电</td></tr><tr><td><strong>Fluent</strong></td><td>流体分析</td><td>流体</td></tr><tr><td><strong>Icepak</strong></td><td>电子热管理</td><td>热+流体</td></tr></tbody></table><h2 id="📊-典型工作流程" tabindex="-1">📊 典型工作流程 <a class="header-anchor" href="#📊-典型工作流程" aria-label="Permalink to &quot;📊 典型工作流程&quot;">​</a></h2><h3 id="步骤-1-创建项目" tabindex="-1">步骤 1：创建项目 <a class="header-anchor" href="#步骤-1-创建项目" aria-label="Permalink to &quot;步骤 1：创建项目&quot;">​</a></h3><ol><li>从工具箱拖动分析系统到项目原理图</li><li>或双击分析系统自动创建</li></ol><h3 id="步骤-2-定义工程数据" tabindex="-1">步骤 2：定义工程数据 <a class="header-anchor" href="#步骤-2-定义工程数据" aria-label="Permalink to &quot;步骤 2：定义工程数据&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>双击 &quot;Engineering Data&quot;</span></span>
<span class="line"><span>├── 添加材料</span></span>
<span class="line"><span>│   ├── 从库中选择</span></span>
<span class="line"><span>│   └── 或创建新材料</span></span>
<span class="line"><span>└── 定义材料属性</span></span>
<span class="line"><span>    ├── 密度</span></span>
<span class="line"><span>    ├── 弹性模量</span></span>
<span class="line"><span>    ├── 泊松比</span></span>
<span class="line"><span>    └── 热导率等</span></span></code></pre></div><h3 id="步骤-3-创建几何" tabindex="-1">步骤 3：创建几何 <a class="header-anchor" href="#步骤-3-创建几何" aria-label="Permalink to &quot;步骤 3：创建几何&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>双击 &quot;Geometry&quot;</span></span>
<span class="line"><span>├── 打开 DesignModeler 或 SpaceClaim</span></span>
<span class="line"><span>├── 创建几何</span></span>
<span class="line"><span>└── 保存并关闭</span></span></code></pre></div><h3 id="步骤-4-模型设置" tabindex="-1">步骤 4：模型设置 <a class="header-anchor" href="#步骤-4-模型设置" aria-label="Permalink to &quot;步骤 4：模型设置&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>双击 &quot;Model&quot;</span></span>
<span class="line"><span>├── 材料分配</span></span>
<span class="line"><span>├── 接触设置</span></span>
<span class="line"><span>├── 网格划分</span></span>
<span class="line"><span>└── 网格质量检查</span></span></code></pre></div><h3 id="步骤-5-设置边界条件" tabindex="-1">步骤 5：设置边界条件 <a class="header-anchor" href="#步骤-5-设置边界条件" aria-label="Permalink to &quot;步骤 5：设置边界条件&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>双击 &quot;Setup&quot;</span></span>
<span class="line"><span>├── 边界条件</span></span>
<span class="line"><span>│   ├── 固定约束</span></span>
<span class="line"><span>│   ├── 载荷</span></span>
<span class="line"><span>│   └── 温度</span></span>
<span class="line"><span>└── 分析设置</span></span></code></pre></div><h3 id="步骤-6-求解" tabindex="-1">步骤 6：求解 <a class="header-anchor" href="#步骤-6-求解" aria-label="Permalink to &quot;步骤 6：求解&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>右键 &quot;Solution&quot; → Solve</span></span>
<span class="line"><span>├── 检查求解状态</span></span>
<span class="line"><span>└── 查看警告/错误</span></span></code></pre></div><h3 id="步骤-7-后处理" tabindex="-1">步骤 7：后处理 <a class="header-anchor" href="#步骤-7-后处理" aria-label="Permalink to &quot;步骤 7：后处理&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>双击 &quot;Results&quot;</span></span>
<span class="line"><span>├── 添加结果</span></span>
<span class="line"><span>│   ├── 变形</span></span>
<span class="line"><span>│   ├── 应力</span></span>
<span class="line"><span>│   └── 应变</span></span>
<span class="line"><span>├── 生成图表</span></span>
<span class="line"><span>└── 导出报告</span></span></code></pre></div><h2 id="⌨️-常用快捷键" tabindex="-1">⌨️ 常用快捷键 <a class="header-anchor" href="#⌨️-常用快捷键" aria-label="Permalink to &quot;⌨️ 常用快捷键&quot;">​</a></h2><h3 id="workbench-快捷键" tabindex="-1">Workbench 快捷键 <a class="header-anchor" href="#workbench-快捷键" aria-label="Permalink to &quot;Workbench 快捷键&quot;">​</a></h3><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td>Ctrl+S</td><td>保存</td></tr><tr><td>Ctrl+Z</td><td>撤销</td></tr><tr><td>Ctrl+Y</td><td>重做</td></tr><tr><td>F5</td><td>刷新</td></tr><tr><td>Ctrl+滚轮</td><td>缩放</td></tr></tbody></table><h3 id="mechanical-快捷键" tabindex="-1">Mechanical 快捷键 <a class="header-anchor" href="#mechanical-快捷键" aria-label="Permalink to &quot;Mechanical 快捷键&quot;">​</a></h3><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td>Ctrl+A</td><td>全选</td></tr><tr><td>Ctrl+鼠标左键</td><td>多选</td></tr><tr><td>F</td><td>适合窗口</td></tr><tr><td>R</td><td>旋转模式</td></tr><tr><td>P</td><td>平移模式</td></tr><tr><td>Z</td><td>窗口缩放</td></tr></tbody></table><h2 id="🔧-常用设置" tabindex="-1">🔧 常用设置 <a class="header-anchor" href="#🔧-常用设置" aria-label="Permalink to &quot;🔧 常用设置&quot;">​</a></h2><h3 id="并行计算设置" tabindex="-1">并行计算设置 <a class="header-anchor" href="#并行计算设置" aria-label="Permalink to &quot;并行计算设置&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Tools → Options → Analysis Settings and Solution</span></span>
<span class="line"><span>├── 并行求解器: 启用</span></span>
<span class="line"><span>├── CPU 数量: 根据系统设置</span></span>
<span class="line"><span>└── GPU 加速: 如果有专业显卡</span></span></code></pre></div><h3 id="内存设置" tabindex="-1">内存设置 <a class="header-anchor" href="#内存设置" aria-label="Permalink to &quot;内存设置&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Tools → Options → Memory</span></span>
<span class="line"><span>├── 最大内存使用: 80%</span></span>
<span class="line"><span>└── 临时文件目录: SSD 路径</span></span></code></pre></div><h3 id="单位设置" tabindex="-1">单位设置 <a class="header-anchor" href="#单位设置" aria-label="Permalink to &quot;单位设置&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Tools → Units</span></span>
<span class="line"><span>├── 长度: mm</span></span>
<span class="line"><span>├── 力: N</span></span>
<span class="line"><span>├── 时间: s</span></span>
<span class="line"><span>├── 温度: °C</span></span>
<span class="line"><span>└── 或选择预设: Metric (mm, kg, s)</span></span></code></pre></div><h2 id="🚨-常见问题" tabindex="-1">🚨 常见问题 <a class="header-anchor" href="#🚨-常见问题" aria-label="Permalink to &quot;🚨 常见问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>问题</th><th>原因</th><th>解决方案</th></tr></thead><tbody><tr><td>启动失败</td><td>许可证问题</td><td>检查许可证服务器连接</td></tr><tr><td>内存不足</td><td>模型太大</td><td>增加内存或简化模型</td></tr><tr><td>网格失败</td><td>几何问题</td><td>修复几何或调整网格设置</td></tr><tr><td>不收敛</td><td>边界条件问题</td><td>调整载荷步或边界条件</td></tr><tr><td>显示异常</td><td>显卡驱动</td><td>更新显卡驱动</td></tr></tbody></table><h2 id="📖-下一步" tabindex="-1">📖 下一步 <a class="header-anchor" href="#📖-下一步" aria-label="Permalink to &quot;📖 下一步&quot;">​</a></h2><p>安装完成后，建议继续学习：</p><ul><li><a href="/simu-learn/ansys/basics/workbench.html">Workbench 界面</a></li><li><a href="/simu-learn/ansys/basics/geometry.html">几何建模</a></li></ul><hr><div class="tip custom-block"><p class="custom-block-title">提示</p><p>ANSYS 安装包较大，建议使用高速网络下载。</p></div><div class="warning custom-block"><p class="custom-block-title">注意</p><p>ANSYS 计算需要大量内存和 CPU 资源，建议使用工作站。</p></div>`,61)])])}const b=s(l,[["render",p]]);export{u as __pageData,b as default};
